INSERT INTO properties (reference, title, title_nl, title_en, description, description_nl, description_en, price, slug_fr, slug_nl, slug_en, surface, rooms, bedrooms, bathrooms, property_type, condition, status, location_city, location_region, location_address, features, energy_rating, published)
VALUES
('SEC-1611', 'Manilva: très beaux appartements 2 chambres', '', '', 'La nature et la mer sont les deux mots qui caractérisent ce nouveau développement à Manilva. Vous jouirez d''une tranquillité hors pair en étant en deuxième ligne de mer. Plusieurs golfs se trouvent à proximité. Votre nouvel appartement sera fait sur mesure pour vous, dans un complexe d''appartements de 2 chambres avec parking, avec vue mer et avec de magnifiques jardins communautaires abritant deux très grandes piscines. Une salle de sport est aussi réservée aux propriétaires. Le tout dans un domaine de plus de 14 000 mètres carrés. La qualité des matériaux, l''excellente isolation acoustique, la climatisation, le chauffage de l''eau par panneaux solaires vous donneront tout le confort d''une habitation de classe C. Prix à partir de 310.000 ? hors frais', '', '', 310000, 'manilva-tres-beaux-appartements-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1612', 'Manilva: Exceptionnels appartements 3 chambres', '', '', 'La nature et la mer sont les deux mots qui caractérisent ce nouveau développement à Manilva. Vous jouirez d''une tranquillité hors pair en étant en deuxième ligne de mer. Plusieurs golfs se trouvent à proximité. Votre nouvel appartement sera fait sur mesure pour vous, dans un complexe d''appartements de 2 ou 3 chambres avec parking, avec vue mer et avec de magnifiques jardins communautaires abritant deux très grandes piscines. Une salle de sport est aussi réservée aux propriétaires. Le tout dans un domaine de plus de 14 000 mètres carrés. La qualité des matériaux, l''excellente isolation acoustique, la climatisation, le chauffage de l''eau par panneaux solaires vous donneront tout le confort d''une habitation de classe C. Prix à partir de 350.000? hors frais', '', '', 350000, 'manilva-exceptionnels-appartements-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1618', 'Algorfa: Magnifiques appartements 2 chambres dans un superbe golf', '', '', 'Cette résidence se love au c?ur d''un des plus beaux golfs de la Costa Blanca. A 100 m du green et à 12km des plages, ces appartements bénéficient d'' excellentes finitions et le choix des matériaux est particulièrement pertinent. Toutes commodités sont disponibles dans les environs tout proches. Tout est parfait pour ceux qui recherchent le calme, la tranquillité, la qualité de vie et le côté pratique. Proposés en deux chambres et deux salles de bains, les habitations du rez-de-chaussée jouissent d''un jardin privatif et d''une grande terrasse; ceux du premier étage d''une belle terrasse et d''un impressionnant solarium. Un espace commun avec piscine et jardin est à disposition des habitants. Possibilité d''une place de parking et d''une remise en souterrain moyennant supplément (àpd 6.000 ? hors frais). Prix: à partir de 283.000 ? hors frais 3 chambres également disponibles : àpd 325.000 ? hors frais', '', '', 283000, 'algorfa-magnifiques-appartements-2-chambres-dans-un-superbe-golf', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1710', 'Roldán: belles villas 2 chambres', '', '', 'Ces nouvelles villas sont situées à Roldán, au sein d''un nouveau resort sécurisé, et sont proches de toutes les facilités telles que bars, restaurants, commerces, installations sportives et parcours de golf. Les plages de la Mar Menor se trouvent à 15 minutes et le nouvel aéroport de Murcie - Corvera à 20 minutes. Les villas 2 chambres disposent de 2 salles de bains, d''une cuisine ouverte donnant sur le living avec baies vitrées vers la terrasse et la piscine privée. 1er étage: vaste solarium Prix: à partir de 299.900 hors frais Inclus dans le prix: - Piscine privée avec pré-installation pour pompe à chaleur et douche solaire extérieure. - Cuisine entièrement meublée et équipée avec four, micro-ondes, réfrigérateur, lave-vaisselle encastré et hotte aspirante. Îlot central en bois. - Éclairage LED à l''intérieur de la maison ainsi qu''à l''extérieur. - Salles de bains entièrement équipées avec meuble, lavabo, miroir avec lumière, parois de douche, toilettes suspendues. - Cuisine d''été sur le solarium. - Place de parking dans la parcelle. Fin des travaux: nov 2026', '', '', 299900, 'roldan-belles-villas-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1629', 'Torrevieja: beaux appartements deux chambres à distance de marche de la plage', '', '', 'Ce nouveau complexe se trouve à 250 mètres de la mer et tous les types de commerces se trouvent dans le quartier. A 40 minutes de l''aéroport et à 20 minutes de plusieurs terrains de golf, cette résidence est composée de 46 appartements, d''une belle piscine commune et d''installations de fitness en extérieur. Le design minimaliste saura séduire les amateurs d''intérieurs contemporains. Le bâtiment se distribue sur deux niveaux; au rez-de-chaussée, les propriétaires jouirons d''une terrasse et d''un jardin privatif de minimum 51 m², ceux du premier profiteront d''un solarium de minimum 71 m². Remise des clés pour septembre 2023 Prix pour un premier étage avec solarium: à partir de 275.000? hors frais', '', '', 275000, 'torrevieja-beaux-appartements-deux-chambres-a-distance-de-marche-de-la-plage', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1796', 'San Miguel de Salinas: appartements 3 chambres très modernes', 'San Miguel de Salinas: zeer moderne appartementen met 3 slaapkamers', '', 'Ces superbes appartements sont situés à San Miguel de Salinas, à proximité de toutes les commodités et à 15 minutes des plages de Torrevieja ou de Campoamor et du centre commercial ''Zenia Boulevard''. Dans les environs immédiats, vous trouverez également de nombreux parcours de golf (Villamartin, Las Colinas, Las Ramblas,...). La résidence, au design très moderne, propose des appartements de 2 ou 3 chambres Les appartements 3 chambres disposent de 2 salles de bains, d''une cuisine ouverte donnant sur le living avec baies vitrées vers la belle terrasse (de minimum 26 m²). Certains appartements du rez-de-chaussée jouissent également d''un jardin. Belle zone commune avec grande piscine et jardins. Prix: à partir de 274.900 ? hors frais Possibilité d''acheter une cave: à partir de 3.900 ? HF Remise des clés: avril 2026 ou sept 2026', 'Deze prachtige appartementen zijn gelegen in San Miguel de Salinas, dicht bij alle voorzieningen en op 15 minuten van de stranden van Torrevieja of Campoamor en het winkelcentrum ''Zenia Boulevard''. In de directe omgeving vindt u ook tal van golfbanen (Villamartin, Las Colinas, Las Ramblas,...). De residentie, met een zeer modern design, heeft appartementen met 2 of 3 slaapkamers. De appartementen met 3 slaapkamers hebben 2 badkamers, een open keuken naar de woonkamer met openslaande deuren naar het prachtige terras (minimaal 26 m²). Sommige appartementen op de begane grond hebben ook een tuin. Mooie gemeenschappelijke zone met groot zwembad en tuinen. Prijs: vanaf ? 274.900 exclusief kosten Oplevering: april 2026 of sept 2026', '', 274900, 'san-miguel-de-salinas-appartements-3-chambres-tres-modernes', 'san-miguel-de-salinas-zeer-moderne-appartementen-met-3-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1685', 'Pilar de la Horadada: magnifiques appartements dans un golf en 2 chambres', '', '', 'Cette résidence se situe idéalement en première ligne de golf et se trouve à 5 minutes en voiture de tous les types de commerces et de services. Les plages et un joli port de plaisance sont à 10 minutes. Les appartements sont spacieux et très lumineux; ils sont distribué sur trois niveaux, ceux du rez-de-chaussée jouissent d''un jardin privé allant de 61 à 81 m², ceux d''un premier étage ont une terrasse de 26m² et ceux du dernier étage ont une grande terrasse et un superbe solarium. De magnifiques jardins et une piscine à débordement rehaussent cette résidence de standing. Une place de parking en plein air est incluse dans le prix. Remise des clés: key ready Prix à partir de 264.900? hors frais pour un rez-de-chaussée', '', '', 264900, 'pilar-de-la-horadada-magnifiques-appartements-dans-un-golf-en-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1732', '!!! DERNIERE UNITE !!! Torrevieja: bel appartement 2 chambres à Los Balcones, avec vue sur les salines de Torrevieja', 'Torrevieja: prachtige appartementen met 2 slaapkamers in Los Balcones, met uitzicht op de zoutmeren van Torrevieja', '', 'Cette nouvelle résidence est idéalement située à ''Los Balcones'', un quartier de Torrevieja, à proximité des ''Salines Roses'' , à seulement 3 km des belles plages de Orihuela Costa et à proximité de nombreux terrains de golf. A distance de marche, vous trouverez des petits commerces, cafés et restaurants. La résidence compte 104 appartements, répartis autour de beaux jardins et de deux grandes piscines communes. Les appartements disposent de 2 chambres, 2 salles de bains, une cuisine ouverte sur le salon/salle à manger avec portes fenêtres donnant sur la terrasse. Les appartements au rez-de-chaussée jouissent d''une grande terrasse, les appartements au 1er étage ont un solarium avec vues sur le ''Lac Rose''. Place de parking souterrain avec remise en option. Prix: Rez-de-chaussée: 275.000? hors frais', '', '', 275000, 'derniere-unite-torrevieja-bel-appartement-2-chambres-a-los-balcones-avec-vue-sur-les-salines-de-torrevieja', 'torrevieja-prachtige-appartementen-met-2-slaapkamers-in-los-balcones-met-uitzicht-op-de-zoutmeren-van-torrevieja', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1878', 'Los Alcazares: beaux appartements 2 chambres sur un golf', '', '', 'Cette nouvelle résidence est située à La Serena Golf, Los Alcazares, à seulement 2 km des plages de la Mar Menor. Le complexe comptera au total 244 appartements 2 ou 3 chambres, répartis en 8 bâtiments, sur 3 niveaux. Les appartements du rez-de-chaussée ont une terrasse et un jardin, ceux du 1er étage jouissent d''une belle terrasse, et ceux du 2ème étage bénéficient d''une terrasse et d''un vaste solarium. Les appartements offrent des vues soit sur les zones communes, soit sur le parcours de golf. Les appartements 2 chambres disposent de 2 salles de bains, ainsi que d''une place de parking et d''une cave en sous-sol. Belle piscine commune avec jardins. Prix: à partir de 255.000 ? hors frais Fin des travaux bloc 5: janvier 2027', '', '', 255000, 'los-alcazares-beaux-appartements-2-chambres-sur-un-golf', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1724', 'Roldán: superbes villas 3 chambres au calme', 'Roldán: prachtige villa''s met 3 slaapkamers in een rustige omgeving', '', 'Ces nouvelles villas sont situées à Roldán, au sein d''un nouveau resort sécurisé, et sont proches de toutes les facilités telles que bars, restaurants, commerces, installations sportives et parcours de golf. Les plages de la Mar Menor se trouvent à 15 minutes et le nouvel aéroport de Murcie - Corvera à 20 minutes. Les villas 3 chambres disposent, au rez-de-chaussée, de 2 chambres, 2 salles de bains et d''une cuisine ouverte donnant sur le living avec baies vitrées vers la terrasse et la piscine privée. 1er étage: 1 chambre et 1 salle de bains et vaste solarium Prix: à partir de 392.500 ? hors frais Inclus dans le prix: - Piscine privée avec pré-installation pour pompe à chaleur et douche solaire extérieure. - Cuisine entièrement meublée et équipée avec four, micro-ondes, réfrigérateur, lave-vaisselle encastré et hotte aspirante. Îlot central en bois. - Éclairage LED à l''intérieur de la maison ainsi qu''à l''extérieur. - Salles de bains entièrement équipées avec meuble, lavabo, miroir avec lumière, parois de douche, toilettes suspendues. - Cuisine d''été sur le solarium. - Place de parking dans la parcelle. Fin des travaux: novembre 2026 1 villa key ready', 'Deze nieuwe villa''s zijn gelegen in Roldán, in een nieuw beveiligd resort, en dichtbij alle voorzieningen zoals bars, restaurants, winkels, sportfaciliteiten en golfbanen. De stranden van de Mar Menor liggen op 15 minuten afstand en de nieuwe luchthaven van Murcia - Corvera op 20 minuten. De villa''s met 3 slaapkamers hebben op de begane grond 2 slaapkamers, 2 badkamers en een open keuken die uitkomt op de woonkamer met openslaande deuren naar het terras en het privézwembad. 1ste verdieping: 1 slaapkamer, 1 badkamer en zonneterras Prijs: vanaf ? 392.500 exclusief kosten Inbegrepen in de prijs: - Privé zwembad met pre-installatie voor warmtepomp en buitendouche op zonne-energie. - Volledig ingerichte en uitgeruste keuken met oven, magnetron, koelkast, ingebouwde vaatwasser en afzuigkap. Centraal houten eiland. - LED verlichting zowel binnen als buiten. - Volledig ingerichte badkamers met meubilair, wastafel, spiegel met licht, doucheschermen, toiletten. - Zomerkeuken op het solarium. - Parkeerplaats op het perceel. Oplevering: nov. 2026', '', 392500, 'roldan-superbes-villas-3-chambres-au-calme', 'roldan-prachtige-villa-s-met-3-slaapkamers-in-een-rustige-omgeving', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1651', 'San Javier: magnifiques appartements deux chambres proches de la mer.', '', '', 'Ce nouveau complexe se situe à quelques minutes à pied des plages d''une part et à proximité du terrain de golf de Roda d''autre part. Toutes les commodités sont disponibles dans le quartier. Le complexe se compose de 87 appartements proposés en deux ou trois chambres, deux salles de bains, une cuisine ouverte sur une salle à manger et un salon donnant sur une grande terrasse avec vue sur les jardins communs et la piscine. L''aménagement des pièces de jour est différent d''un appartement à l''autre. Chaque appartement dispose d''une place de parking en sous-sol. Les unités du rez-de-chaussée jouissent de très grandes terrasses (de 23m² à 85m²) et celles du dernier étage sont dotées d''un beau solarium en plus de la terrasse. Prix: à partir de 235.000 ? hors frais Fin des travaux : juin ou septembre 2025', '', '', 235000, 'san-javier-magnifiques-appartements-deux-chambres-proches-de-la-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1652', 'San Javier: très beaux appartements en trois chambres près de la mer', '', '', 'Ce nouveau complexe se situe à quelques minutes à pied des plages d''une part et à proximité du terrain de golf de Roda d''autre part. Toutes les commodités sont disponibles dans le quartier. Le complexe se compose de 87 appartements proposés en deux ou trois chambres, deux salles de bains, une cuisine ouverte sur une salle à manger et un salon donnant sur une grande terrasse avec vue sur les jardins communs et la piscine. L''aménagement des pièces de jour est différent d''un appartement à l''autre. Chaque appartement dispose d''une place de parking en sous-sol. Les unités du rez-de-chaussée jouissent de très grandes terrasses (de 23m² à 85m²) et celles du dernier étage sont dotées d''un beau solarium en plus de la terrasse. Prix: à partir de 265.000 ? hors frais', '', '', 265000, 'san-javier-tres-beaux-appartements-en-trois-chambres-pres-de-la-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1653', 'Algorfa: Luxueuse villa trois chambres en première ligne de golf', '', '', 'Lovées au c?ur d''un des plus beaux golf de la Costa Blanca, ces nouvelles villas bénéficient de vues splendides sur le parcours. Dotés de finitions luxueuses, elles sont proposées en trois chambres et deux salles de bains. L''aéroport d''Alicante se situe à 35 minutes en voiture et les belles plages de Guardamar sont à moins de 20 minutes. Le village d''Algorfa et ses commerces sont à 3 minutes. La villa dispose d''un chauffage sol dans toutes les pièces, d''un système de domotique et est proposée en plain pied avec un grand garage pour deux véhicules en sous-sol. Le reste du niveau -1 est aménageable selon vos envies. Les villas jouissent en outre d''une piscine à débordement privée, d''un espace barbecue et d''un magnifique jardin aménagé allant de minimum 465 m². La chambre parentale dispose d''un dressing et d''une salle de bain en suite. La cuisine ouverte est équipée d''un îlot central. Prix à partir de 980.000? hors frais', '', '', 980000, 'algorfa-luxueuse-villa-trois-chambres-en-premiere-ligne-de-golf', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1654', 'Algorfa: Luxueuses villas trois chambres en première ligne de golf', '', '', 'Lovées au c?ur d''un des plus beaux golf de la Costa Blanca, ces nouvelles villas bénéficient de vues splendides sur le parcours. Dotés de finitions luxueuses, elles sont proposées en trois chambres et trois salles de bains. L''aéroport d''Alicante se situe à 35 minutes en voiture et les belles plages de Guardamar sont à moins de 20 minutes. Le village d''Algorfa et ses commerces sont à 3 minutes. La villa dispose d''un chauffage sol dans toutes les pièces, d''un système de domotique et est proposée en plain pied avec un grand garage pour deux véhicules en sous-sol. Le reste du niveau -1 est aménageable selon vos envies. Les villas jouissent en outre d''une piscine (à débordement) privée, d''un espace barbecue, d''une espace chill out , d''un jacuzzi et d''un magnifique jardin aménagé allant de minimum 469 m². La chambre parentale au premier étage dispose d''un dressing et d''une salle de bain en suite. La cuisine ouverte est équipée d''un îlot central. Prix à partir de 1.250.000? hors frais', '', '', 1250000, 'algorfa-luxueuses-villas-trois-chambres-en-premiere-ligne-de-golf', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1661', 'Denia: en 1ère ligne de mer, superbes appartements 2 chambres', '', '', 'Cette nouvelle résidence comptant 100 appartements est idéalement située en PREMIÈRE LIGNE DE MER, à Dénia, à côté de l''une des plages les mieux notées d''Espagne. Les appartements, répartis sur 4 niveaux, disposent de 2 chambres et 2 salles de bains, d''une cuisine ouverte sur le séjour ainsi que d''une vaste terrasse. La résidence compte de beaux jardins aménagés, une belle piscine commune ainsi qu''un parking souterrain. Prix: à partir de 355.000 ? hors frais Inclus: hotte, taque à induction et four, place de parking.', '', '', 355000, 'denia-en-1ere-ligne-de-mer-superbes-appartements-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1667', 'Rojales: villas adossées haut de gamme en première ligne de golf', '', '', 'Ces nouvelles villas se trouvent en première ligne du golf de la Marquesa. Depuis votre terrasse, vous jouirez d''une superbe vue sur le green et sur la nature environnante. Elles sont proposées en trois chambres dont une en suite parentale avec un dressing et une salle de bains privative. De généreuses caves accueillent soit un garage pour deux véhicules, soit vous permettront de stocker vos clubs de golfs, votre mobilier extérieur ou pourront être affectées à l''usage que vous souhaiterez. Chaque unité jouit d''une belle piscine privée! L''accès au green peut se faire depuis votre jardin. Toutes les commodités se trouvent à très courte distance: soit sur Rojales, soit sur Ciudad Quesada. Les plages sont à moins de 10 minutes en voiture. Remise des clés mars 2023. Solarium possible en option. Électroménagers inclus dans le prix Prix à partir de 749.000? hors frais', '', '', 749000, 'rojales-villas-adossees-haut-de-gamme-en-premiere-ligne-de-golf', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1670', 'Orihuela Costa: Magnifiques villas de luxe en 4 chambres', '', '', 'Ce nouveau complexe de luxueuses villas se situe à 200m des magnifiques plages de Aguamarina. La zone propose des accès directs à tous les sports nautiques et équestres, aux bars et restaurants, aux 15 terrains de golf et à tous les types de commerces. Les connexions avec les aéroports de Murcie ( 30 minutes) ou d''Alicante (45 minutes) se font très facilement via la nationale 332 ou l''autoroute AP7. Les villas jouissent de matériaux de très haute qualité et des dernières techniques de construction et sont construites sur des parcelles de 500m². Elles sont proposées en différentes versions et avec une multitude d''options qui feront de votre villa un lieu unique. Prix à partir de 910.000? hors frais', '', '', 910000, 'orihuela-costa-magnifiques-villas-de-luxe-en-4-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1682', 'DERNIERES UNITES ! Los Balcones - Torrevieja: beaux appartements 2 chambres', '', '', 'Cette nouvelle résidence est idéalement située à ''Los Balcones'', un quartier de Torrevieja, à 5 minutes des belles plages de Orihuela Costa et de nombreux terrains de golf. A distance de marche, vous trouverez des petits commerces, cafés et restaurants. La résidence offre de jolies vues sur les salines de Torrevieja et comptera 136 appartements, soit au rez-de-chaussée avec terrasse à l''avant et à l''arrière (25,35 m² + 31,40 m², soit au 1er étage avec terrasse (18,37 m²) et solarium (85.82 m²). Les appartements 2 chambres disposent de 2 salles de bains, d''une cuisine ouverte sur le séjour avec baies vitrées vers la terrasse. La résidence compte 3 piscines communes, un jacuzzi, une plaine de jeux, un mini-golf, un terrain de paddle et une zone fitness. Prix: Rez-de-chaussée: à partir de 269.900 ? hors frais Parking et caves en sous-sol inclus Fin des travaux: juin 2025', '', '', 269900, 'dernieres-unites-los-balcones-torrevieja-beaux-appartements-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1686', 'Pilar de la Horadada: magnifiques appartements dans un golf en 3 chambres', '', '', 'Cette nouvelle phase ne comprend que 20 unités de 2 ou 3 chambres et deux salles de bains. Elle se situe idéalement en première ligne de golf et se trouve à 5 minutes en voiture de tous les types de commerces et de services. Les plages et un joli port de plaisance sont à 10 minutes. Les appartements sont spacieux et très lumineux; ils sont distribué sur trois niveaux, ceux du rez-de-chaussée jouissent d''un jardin privé allant de 61 à 81 m², ceux d''un premier étage ont une terrasse de 26m² et ceux du dernier étage ont une grande terrasse et un superbe solarium. De magnifiques jardins et une piscine à débordement rehaussent cette résidence de standing. Une place de parking en plein air est incluse dans le prix. A partir de 334.900? hors frais pour un rez', '', '', 334900, 'pilar-de-la-horadada-magnifiques-appartements-dans-un-golf-en-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1883', 'La Finca: magnifique villa 3 chambres dans un golf prestigieux', '', '', 'Magnifique villa contemporaine 3 chambres située dans un superbe domaine de golf. Vous serez séduits par ses belles vues sur le green et sur la montagne. Les superbes plages de Guardamar se trouvent à 12 km. La villa comporte 3 chambres, 2 salles de bains, une cuisine ouverte sur le salon et la salle à manger. Jardin, terrasse, solarium et piscine privée. Prix: à partir de 509.000 ? hors frais Inclus: - système domotique avec volets électriques - climatisation - électroménagers - Piscine 7m x 3m - Chauffage au sol dans les salles de bains - Jardin aménagé avec système d''irrigation Fin des travaux: 3ème ou 4ème trimestre 2025', '', '', 509000, 'la-finca-magnifique-villa-3-chambres-dans-un-golf-prestigieux', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1703', 'DERNIERE UNITE ! Pilar de la Horadada: appartements de luxe en 2 chambres', '', '', 'Ce nouveau développement de 16 appartements se situe à 5 minutes en voiture des belles plages de Torre de la Horadada et est proche de toutes les commodités. La résidence jouit d''une belle piscine commune. Les appartements du premier étage d''un généreux solarium avec cuisine d''été et pergola. Les électroménagers, le chauffage sol dans les salles d''eau et les luminaires sont inclus dans le prix Prix: Rez-de-chaussée: 250.900 ? hors frais Fin des travaux: avril 2025', '', '', 250900, 'derniere-unite-pilar-de-la-horadada-appartements-de-luxe-en-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1706', 'Gran Alacant: superbes appartements 2 chambres à proximité de la mer', '', '', 'Cette nouvelle résidence est idéalement située à Gran Alacant, à proximité des plages de Carabassi, tout près d''un parc naturel, et à seulement 20 minutes d''Alicante et de Elche. La résidence comptera 120 appartements 2 et 3 chambres, jouissant d''une vue sur le parc naturel, sur les espaces communs et les jardins avec piscines communes et aire de jeux pour enfants. Chaque appartement dispose d''une cuisine ouverte donnant sur le living avec portes-fenêtres vers la terrasse, de 2 chambres, de 2 salles de bains, d''un parking souterrain, d''un débarras et d''une buanderie. Les appartements du dernier étage jouissent d''un solarium. Prix 2 chambres: de 310.000 ? à 325.000 ? hors frais Inclus: climatisation, taque vitrocéramique, four et hotte Date de livraison prévue: Avril 2025', '', '', 310000, 'gran-alacant-superbes-appartements-2-chambres-a-proximite-de-la-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1839', 'San Miguel de Salinas : superbe appartement 3 chambres, entièrement équipé, clé en mains !', '', '', 'Ce superbe appartement 3 chambres est situé à San Miguel de Salinas, à 15 minutes des belles plages de Mil Palmeras et de Cabo Roig. Plusieurs parcours de golf se trouvent à proximité, dont Las Colinas à 3 minutes, Villamartin à 10 min et le Golf de La Finca à 15 minutes. A moins de 15 minutes, vous trouverez de nombreux restaurants et magasins. L''appartement est situé au 1er étage d''une petite résidence avec piscine commune et comprend 3 chambres, 2 salles de bains, une cuisine équipée ouverte sur un beau living et 2 terrasses, dont un solarium de plus de 70 m². Il est vendu entièrement équipé (meubles, climatisation, électroménagers,...). Prix: 235.000 ? hors frais Licence touristique', '', '', 235000, 'san-miguel-de-salinas-superbe-appartement-3-chambres-entierement-equipe-cle-en-mains', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1707', 'Gran Alacant: très beaux appartements 3 chambres à proximité de la mer', '', '', 'Cette nouvelle résidence est idéalement située à Gran Alacant, à proximité des plages de Carabassi, tout près d''un parc naturel, et à seulement 20 minutes d''Alicante et de Elche. La résidence comptera 120 appartements 2 et 3 chambres, jouissant d''une vue sur le parc naturel, sur les espaces communs et les jardins avec piscines communes et aire de jeux pour enfants. Chaque appartement dispose d''une cuisine ouverte donnant sur le living avec portes-fenêtres vers la terrasse, de 2 chambres, de 2 salles de bains, d''un parking souterrain, d''un débarras et d''une buanderie. Prix: de 245.000 ? à 295.000 ? hors frais Inclus: climatisation, taque vitrocéramique, four et hotte Date de livraison prévue: Juin 2024 ou octobre 2024', '', '', 285000, 'gran-alacant-tres-beaux-appartements-3-chambres-a-proximite-de-la-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1735', 'Las Colinas: villa 3 chambres au design unique', 'Las Colinas: villa met 3 slaapkamers en een uniek design', '', 'Superbe villa 3 chambres au design unique, nichée dans l''un des plus beaux golfs d''Europe, Las Colinas Golf & Country Club. Situation exceptionnelle dans une vallée de 330 hectares entre les collines et face à la mer Méditerranée. Un lieu idéal pour s?évader et pour profiter des 200.000 m² de zone naturelle. Le golf de Las Colinas est situé à coutre distance de deux aéroports internationaux (Alicante et Murcia). Les superbes plages de Campoamor et de Cabo Roig se trouvent à 10 minutes en voiture. Facilités du resort: - Golf 18 trous - Académie de Golf - Terrains de tennis et de paddle - Beachclub à Campoamor - Clubhouse avec divers restaurants - Fitness - Wellness - Circuits de VTT - Mini-market La villa est agencée comme suit: Niveau -1: 1 chambre, 1 salle de bains, accès à la terrasse et au jardin Rez-de-chaussée: cuisine ouverte sur le living avec baies vitrées vers la terrasse avec piscine, 1 chambre, 1 salle de bains, WC séparé 1er étage: 3ème chambre avec salle de bains Superficie construite: 240 m² Parcelle: 1075 m² Terrasses: 109 m² Système domotique Électroménagers inclus Pré-installation climatisation (Air zone) Garage Prix: 1.485.000 ? hors frais', 'Schitterende villa met 3 slaapkamers, met een uniek design, gelegen in een van de mooiste golfbanen van Europa, Las Colinas Golf & Country Club. Uitzonderlijke ligging in een 330 hectare grote vallei tussen de heuvels en met uitzicht op de Middellandse Zee. Een ideale plek om te ontsnappen en te genieten van de 200.000 m² natuurgebied. De golfbaan Las Colinas ligt op korte afstand van twee internationale luchthavens (Alicante en Murcia). De prachtige stranden van Campoamor en Cabo Roig liggen op 10 minuten rijden. Resortfaciliteiten: - 18-holes golfbaan - Golf Academy - Tennis- en paddlebanen - Beachclub in Campoamor - Clubhuis met diverse restaurants - Fitness - Wellness - Mountainbike circuits - Mini markt De villa is als volgt ingedeeld: Niveau -1: 1 slaapkamer, 1 badkamer, toegang tot het terras en de tuin Begane grond: open keuken naar de woonkamer met openslaande deuren naar het terras met zwembad, 1 slaapkamer, 1 badkamer, apart toilet 1ste verdieping: 3de slaapkamer met badkamer Bebouwde oppervlakte: 240 m² Perceel: 1075 m² Terrassen: 109 m² Domotica systeem Elektrische apparaten Garage Prijs: ? 1.485.000,- exclusief kosten', '', 1485000, 'las-colinas-villa-3-chambres-au-design-unique', 'las-colinas-villa-met-3-slaapkamers-en-een-uniek-design', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false)
